// CLX LinkedIn Outreach v1 — Resolve input
// Accepts either the Schedule Trigger (batch mode) or the Manual Webhook
// ({ body: { lead_id } }). When a lead_id is provided, single-lead mode.
// Otherwise batch mode pulls Campaign Assigned + preferred_channel=linkedin.

const input = $input.item.json;
const leadId = (input.body && input.body.lead_id) || input.lead_id || null;

return {
  json: {
    lead_id: leadId,
    mode: leadId ? 'single' : 'batch'
  }
};

// CLX LinkedIn Outreach v1 — Normalize + preflight gates
// Gates (short-circuit via _skip):
//   1. lead row missing
//   2. preferred_channel is not 'linkedin'
//   3. no linkedin_url on the lead
//   4. already attempted LinkedIn (channels_attempted includes 'linkedin')

const rows = $input.item.json;
const lead = Array.isArray(rows) ? rows[0] : rows;

if (!lead || !lead.id) {
  return { json: { _skip: true, skip_reason: 'lead_not_found' } };
}
if (String(lead.preferred_channel || '').toLowerCase() !== 'linkedin') {
  return { json: { _skip: true, skip_reason: 'preferred_channel_mismatch', lead_id: lead.id } };
}
if (!lead.linkedin_url) {
  return { json: { _skip: true, skip_reason: 'no_linkedin_url', lead_id: lead.id, client_id: lead.client_id || null } };
}
const attempted = Array.isArray(lead.channels_attempted) ? lead.channels_attempted : [];
if (attempted.includes('linkedin')) {
  return { json: { _skip: true, skip_reason: 'already_attempted_linkedin', lead_id: lead.id, client_id: lead.client_id || null } };
}

return { json: lead };

// CLX LinkedIn Outreach v1 — Daily-cap gate
// Unipile / LinkedIn platform tolerates ~20 new connections / messages
// per account per day. We cap at 18 per client to keep a buffer for
// retries and in-flight calls.

const lead = $('Normalize Lead').first().json;
if (lead._skip) return { json: lead };

const used = Number($input.item.json) || 0;
const CAP = 18;

if (used >= CAP) {
  return { json: { _skip: true, skip_reason: 'linkedin_daily_cap_exceeded', sends_today: used, cap: CAP, lead_id: lead.id, client_id: lead.client_id || null } };
}

return { json: { ...lead, sends_today: used, cap: CAP } };

// CLX LinkedIn Outreach v1 — Compose LinkedIn connection + first-message
// We send a personalised connection request + opening message using the
// campaign copy the Campaign Router already assigned. Kept short because
// LinkedIn platform enforces a 300-char invite-note limit.

const lead = $input.item.json;

const firstName = (lead.full_name || '').split(' ')[0] || 'there';
const vp = lead.campaign_value_proposition || 'help companies automate sales outreach';

const invite_note = `Hi ${firstName} — I work with ${lead.industry || 'businesses'} in ${lead.city || 'your area'} and thought we might connect. We ${vp}. Open to a 15-min chat?`.slice(0, 290);

const first_message = `Hi ${firstName}, thanks for connecting! Quick question — ${lead.campaign_pain_point || 'most ' + (lead.industry || 'teams') + ' we talk to are stretched thin on manual follow-up'}. ${lead.campaign_call_to_action || 'Worth a quick chat?'}`;

return {
  json: {
    ...lead,
    invite_note,
    first_message
  }
};

// CLX LinkedIn Outreach v1 — Parse Unipile response
// Extracts chat_id / error to log downstream. Unipile invite endpoint
// returns { provider_id, object: 'Invitation', status } on success, or
// { error, message } on failure. continueOnFail upstream means a raw
// error body may land here — treat anything without a status/object
// field as a failure and capture the body verbatim for scan_errors.

const resp = $input.item.json || {};
const lead = $('Compose Message').first().json;

const ok = !!(resp.object === 'Invitation' || resp.status === 'sent' || resp.chat_id);
const chat_id = resp.chat_id || resp.provider_id || null;
const error_message = ok ? null : (resp.message || resp.error || JSON.stringify(resp).slice(0, 500));

return {
  json: {
    ...lead,
    unipile_ok: ok,
    unipile_chat_id: chat_id,
    unipile_error: error_message
  }
};

// CLX LinkedIn Outreach v1 — Prep lead update
// Marks the lead as attempted via LinkedIn (append to channels_attempted)
// and bumps lead_status if the send succeeded. On failure we leave the
// status as Campaign Assigned so the router can re-route the lead via
// email/whatsapp/voice on the next tick.

const parsed = $('Parse Unipile Response').first().json;
const lead = $('Compose Message').first().json;

const attempted = Array.isArray(lead.channels_attempted) ? [...lead.channels_attempted] : [];
if (!attempted.includes('linkedin')) attempted.push('linkedin');

const body = {
  p_lead_id: lead.id,
  p_fields: {
    channels_attempted: attempted,
    last_channel_attempted: 'linkedin',
    last_channel_attempted_at: new Date().toISOString(),
    lead_status: parsed.unipile_ok ? 'Outreach Sent' : 'Campaign Assigned'
  }
};

return { json: { ...parsed, rpc_body: JSON.stringify(body) } };
